#include<bits/stdc++.h>
using namespace std;
int n,t,dp[110][30010],a[110],c[110],w;
int main()
{
    scanf("%d%d",&n,&t);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    dp[1][a[1]+10000]=1;
    dp[2][a[1]-a[2]+10000]=-1;
    for(int i=3;i<=n;i++)
    {
        for(int j=-10000;j<=10000;j++)
        {
            if(dp[i-1][j+10000]==0)
            {
                continue;
            }
            dp[i][j+a[i]+10000]=1;
            dp[i][j-a[i]+10000]=-1;
        }
    }
    int now=t;
    for(int i=n;i>=2;i--)
    {
        c[i]=dp[i][now+10000];
        if(c[i]==-1)
        {
            now+=a[i];
        }
        else
        {
            now-=a[i];
        }
    }
    int cnt=0;
    for(int i=2;i<=n;i++)
    {
        if(c[i]==1)
        {
            printf("%d\n",i-cnt-1);
            cnt++;
        }
    }
    for(int i=2;i<=n;i++)
    {
        if(c[i]==-1)
        {
            printf("1\n");
        }
    }
    return 0;
}
